--
-- Table structure for table `studies`
--

DROP TABLE IF EXISTS `studies`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `studies` (
  `study_id` int NOT NULL AUTO_INCREMENT,
  `nct_id` varchar(20) NOT NULL,
  `title` text,
  `acronym` varchar(50) DEFAULT NULL,
  `status` varchar(50) DEFAULT NULL,
  `phase` varchar(50) DEFAULT NULL,
  `study_type` varchar(50) DEFAULT NULL,
  `start_date` date DEFAULT NULL,
  `completion_date` date DEFAULT NULL,
  `primary_completion_date` date DEFAULT NULL,
  `enrollment` int DEFAULT NULL,
  `enrollment_type` varchar(20) DEFAULT NULL,
  `brief_summary` text,
  `eligibility_criteria` text,
  `minimum_age` varchar(20) DEFAULT NULL,
  `maximum_age` varchar(20) DEFAULT NULL,
  `gender` varchar(20) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  `updated_at` timestamp NULL DEFAULT CURRENT_TIMESTAMP,
  PRIMARY KEY (`study_id`),
  UNIQUE KEY `nct_id` (`nct_id`),
  KEY `idx_studies_status` (`status`),
  KEY `idx_studies_phase` (`phase`),
  KEY `idx_studies_start_date` (`start_date`)
) ENGINE=InnoDB AUTO_INCREMENT=5577 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

